# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

from decimal import Decimal, ROUND_HALF_UP
import uuid

DISCOUNT_MAP = {
    'basic': Decimal('0.00'),
    'premium': Decimal('0.15'),
    'enterprise': Decimal('0.30')
}

def _round_currency(amount: Decimal) -> Decimal:
    return amount.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)

def _cart_total(cart_items) -> Decimal:
    total = Decimal('0.00')
    for item in cart_items:
        price = Decimal(str(item['price']))
        qty = int(item.get('quantity', 1))
        if price < 0 or qty < 0:
            raise ValueError('Invalid price or quantity')
        total += price * qty
    return _round_currency(total)

def _apply_discount(amount: Decimal, rate: Decimal) -> Decimal:
    return _round_currency(amount * (Decimal('1.00') - rate))

def _gateway_charge(amount: Decimal, payment_details):
    if amount <= 0:
        raise ValueError('Charge amount must be greater than zero')
    return {
        'status': 'success',
        'amount_charged': float(amount),
        'transaction_id': str(uuid.uuid4()),
        'payment_method': payment_details.get('method', 'unknown')
    }

def process_payment(user, cart_items, payment_details):
    role = getattr(user, 'role', None)
    if role not in DISCOUNT_MAP:
        raise ValueError('Unsupported user role')
    total = _cart_total(cart_items)
    total_after_discount = _apply_discount(total, DISCOUNT_MAP[role])
    return _gateway_charge(total_after_discount, payment_details)